#include <stdio.h>

int main() {
    double pop_a = 90000.0;
    double pop_b = 200000.0;
    double taxa_a = 0.03;
    double taxa_b = 0.015;
    int anos = 0;

    while (pop_a < pop_b) {
        pop_a = pop_a * (1.0 + taxa_a);
        pop_b = pop_b * (1.0 + taxa_b);
        anos++;
    }

    printf("Numero de anos para A atingir ou ultrapassar B: %d\n", anos);
    printf("Populacao final de A: %.2f\n", pop_a);
    printf("Populacao final de B: %.2f\n", pop_b);

    return 0;
}


